  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  message_id uuid REFERENCES public.messages(id) ON DELETE CASCADE NOT NULL,
  previous_content text NOT NULL,
  edited_by uuid REFERENCES auth.users(id) NOT NULL,
