-- Drop the vulnerable policy that allows email-based access
DROP POLICY IF EXISTS "Guests can view their bookings by email" ON public.bookings;

-- Create a more secure policy that requires proper authentication
CREATE POLICY "Booking owners can view their bookings"
ON public.bookings
FOR SELECT
USING (auth.uid() = user_id);

-- Phase 1, Step 3: Remove Conversation Stats Public Access
-- Drop the overly permissive ALL policy
DROP POLICY IF EXISTS "System can manage conversation stats" ON public.conversation_stats;

-- Participant-restricted SELECT policy already exists
-- System updates will use service role key instead of public policy-- Fix Bookings Data Exposure: Remove public INSERT policy
-- This prevents attackers from scraping customer contact information

-- Drop the vulnerable public INSERT policy
DROP POLICY IF EXISTS "Anyone can create bookings" ON public.bookings;

-- Create a secure policy that only allows authenticated booking owners to insert
-- Bookings for guests will be created via the edge function using service role
CREATE POLICY "Booking owners can create bookings"
ON public.bookings
FOR INSERT
WITH CHECK (auth.uid() = user_id);

-- Note: The create-booking edge function now uses service role key to bypass RLS
-- and securely handle guest bookings with proper validation-- Phase 1: Create user_preferences table for secure UI state storage
-- This replaces localStorage role switching which could be manipulated
CREATE TABLE IF NOT EXISTS public.user_preferences (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  preferred_role_view TEXT,
  created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now(),
  updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now(),
  UNIQUE(user_id)
);

-- Enable RLS on user_preferences
ALTER TABLE public.user_preferences ENABLE ROW LEVEL SECURITY;

-- Users can only manage their own preferences
CREATE POLICY "Users can view their own preferences"
ON public.user_preferences
FOR SELECT
USING (auth.uid() = user_id);

CREATE POLICY "Users can insert their own preferences"
ON public.user_preferences
FOR INSERT
WITH CHECK (auth.uid() = user_id);

CREATE POLICY "Users can update their own preferences"
ON public.user_preferences
FOR UPDATE
USING (auth.uid() = user_id);

-- Add updated_at trigger
CREATE TRIGGER update_user_preferences_updated_at
BEFORE UPDATE ON public.user_preferences
FOR EACH ROW
EXECUTE FUNCTION public.update_updated_at_column();

