-- Function to check rate limiting for verification attempts
CREATE OR REPLACE FUNCTION public.check_verification_rate_limit(
  _user_id uuid,
  _verification_type text,
  _action text
)
RETURNS jsonb
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  recent_attempts integer;
  result jsonb;
BEGIN
  -- Count attempts in last 15 minutes
  SELECT COUNT(*) INTO recent_attempts
  FROM verification_attempts
  WHERE user_id = _user_id
    AND verification_type = _verification_type
    AND action = _action
    AND created_at > now() - interval '15 minutes';
  
  -- Allow max 3 send attempts per 15 minutes
  IF _action = 'send' OR _action = 'resend' THEN
    IF recent_attempts >= 3 THEN
      RETURN jsonb_build_object(
        'allowed', false,
        'message', 'Too many attempts. Please wait 15 minutes.',
        'attempts', recent_attempts
      );
    END IF;
  END IF;
  
  -- Allow max 5 verify attempts per 15 minutes
  IF _action = 'verify' THEN
    IF recent_attempts >= 5 THEN
      RETURN jsonb_build_object(
        'allowed', false,
        'message', 'Too many verification attempts. Please request a new code.',
        'attempts', recent_attempts
      );
    END IF;
  END IF;
  
  RETURN jsonb_build_object(
    'allowed', true,
    'attempts', recent_attempts
  );
END;
$$;

-- Function to clean up expired verifications (run periodically)
CREATE OR REPLACE FUNCTION public.cleanup_expired_verifications()
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  DELETE FROM email_verifications WHERE expires_at < now() AND verified_at IS NULL;
  DELETE FROM phone_verifications WHERE expires_at < now() AND verified_at IS NULL;
  
  -- Delete old verification attempts (keep for 30 days)
  DELETE FROM verification_attempts WHERE created_at < now() - interval '30 days';
END;
$$;-- Fix security warnings: Add SET search_path to functions that are missing it

CREATE OR REPLACE FUNCTION public.notify_new_message()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $function$
DECLARE
  recipient_id UUID;
BEGIN
  -- Get all participants except the sender
  FOR recipient_id IN
    SELECT cp.user_id
    FROM conversation_participants cp
    WHERE cp.conversation_id = NEW.conversation_id
    AND cp.user_id != NEW.sender_id
  LOOP
    INSERT INTO public.notifications (user_id, title, message, type, action_url, metadata)
    VALUES (
      recipient_id,
      'New message',
      LEFT(NEW.content, 100),
      'message',
      '/messages',
      jsonb_build_object('conversation_id', NEW.conversation_id, 'message_id', NEW.id)
    );
  END LOOP;
  
  RETURN NEW;
END;
$function$;

CREATE OR REPLACE FUNCTION public.create_read_receipt()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $function$
BEGIN
  -- Create read receipt when notification is marked as read
  IF NEW.is_read = true AND OLD.is_read = false THEN
    INSERT INTO public.message_read_receipts (message_id, user_id, read_at)
    VALUES (NEW.message_id, NEW.user_id, NEW.read_at)
    ON CONFLICT (message_id, user_id) DO UPDATE
    SET read_at = NEW.read_at;
  END IF;
  RETURN NEW;
END;
$function$;-- Add audit logging for pipeline changes
