$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = '';-- Fix security warning by setting search_path on generate_share_token function
DROP FUNCTION IF EXISTS generate_share_token();

CREATE OR REPLACE FUNCTION generate_share_token()
RETURNS TEXT 
LANGUAGE plpgsql 
SECURITY DEFINER 
SET search_path = public
AS $$
BEGIN
  RETURN encode(gen_random_bytes(32), 'base64');
END;
$$;-- Fix share token generation to use built-in functions
DROP FUNCTION IF EXISTS generate_share_token();

CREATE OR REPLACE FUNCTION generate_share_token()
RETURNS TEXT 
LANGUAGE plpgsql 
SECURITY DEFINER 
SET search_path = public
AS $$
DECLARE
  token TEXT;
BEGIN
  -- Generate a secure random token using gen_random_uuid and md5
  token := replace(gen_random_uuid()::text, '-', '') || replace(gen_random_uuid()::text, '-', '');
  RETURN encode(decode(token, 'hex'), 'base64');
END;
$$;-- Add profile_slug column to profiles table
ALTER TABLE profiles ADD COLUMN IF NOT EXISTS profile_slug TEXT;

-- Create unique index on profile_slug
CREATE UNIQUE INDEX IF NOT EXISTS profiles_profile_slug_unique ON profiles(profile_slug) WHERE profile_slug IS NOT NULL;

-- Function to generate slug from name
CREATE OR REPLACE FUNCTION generate_profile_slug(name TEXT)
RETURNS TEXT
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  base_slug TEXT;
  final_slug TEXT;
  counter INTEGER := 0;
BEGIN
  -- Convert name to lowercase, replace spaces/special chars with hyphens
  base_slug := lower(regexp_replace(trim(name), '[^a-zA-Z0-9]+', '-', 'g'));
  base_slug := trim(both '-' from base_slug);
  
  -- Ensure slug is not empty
  IF base_slug = '' THEN
    base_slug := 'user';
  END IF;
  
  final_slug := base_slug;
  
  -- Check if slug exists, if so add counter
  WHILE EXISTS (SELECT 1 FROM profiles WHERE profile_slug = final_slug) LOOP
    counter := counter + 1;
    final_slug := base_slug || '-' || counter;
  END LOOP;
  
  RETURN final_slug;
END;
$$;

-- Update existing profiles to have slugs based on their names
