  created_at timestamp with time zone NOT NULL DEFAULT now(),
  created_by uuid REFERENCES auth.users(id),
  UNIQUE(task_id, depends_on_task_id),
  -- Prevent self-referencing dependencies
  CHECK (task_id != depends_on_task_id)
);

