-- Create SECURITY DEFINER SET search_path = '' function to check conversation access
CREATE OR REPLACE FUNCTION public.can_access_conversation_storage(
  _conversation_id uuid
)
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.conversation_participants cp
    WHERE cp.conversation_id = _conversation_id
      AND cp.user_id = auth.uid()
  );
$$;

-- Create SECURITY DEFINER SET search_path = '' function to check if user owns a message attachment
CREATE OR REPLACE FUNCTION public.owns_message_attachment(
  _file_path text
)
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT EXISTS (
    SELECT 1 
    FROM public.message_attachments ma
    JOIN public.messages m ON m.id = ma.message_id
    WHERE ma.file_path = _file_path
      AND m.sender_id = auth.uid()
  );
$$;

