-- Create SECURITY DEFINER SET search_path = '' function to check if user is module expert
CREATE OR REPLACE FUNCTION public.is_module_expert(_user_id uuid, _module_id uuid)
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT EXISTS (
    SELECT 1
    FROM module_experts me
    JOIN expert_profiles ep ON me.expert_id = ep.id
    WHERE me.module_id = _module_id
      AND ep.user_id = _user_id
  )
$$;

-- Create SECURITY DEFINER SET search_path = '' function to check if user owns the course
CREATE OR REPLACE FUNCTION public.is_course_owner(_user_id uuid, _course_id uuid)
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT EXISTS (
    SELECT 1
    FROM courses
    WHERE id = _course_id
      AND created_by = _user_id
  )
$$;

