CREATE OR REPLACE FUNCTION public.generate_api_key(
  p_company_id UUID,
  p_name VARCHAR,
  p_scopes TEXT[],
  p_rate_limit_per_hour INTEGER DEFAULT 1000,
  p_created_by UUID DEFAULT NULL
)
RETURNS JSONB
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_key TEXT;
  v_prefix VARCHAR(15);
  v_hash VARCHAR(64);
  v_id UUID;
  v_raw_bytes BYTEA;
