JOIN booking_links bl ON b.booking_link_id = bl.id
WHERE b.created_at > NOW() - INTERVAL '30 days'
GROUP BY bl.user_id, b.active_video_platform;-- Comprehensive Security Fixes: Fix SECURITY DEFINER SET search_path = '' views, functions, and materialized view exposure
