CREATE OR REPLACE FUNCTION public.register_listener(p_session_id uuid, p_user_id uuid DEFAULT NULL::uuid, p_ip_address text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_listener_id UUID;
BEGIN
  INSERT INTO live_session_listeners (session_id, user_id, ip_address, is_active)
  VALUES (p_session_id, p_user_id, p_ip_address, true)
  ON CONFLICT (session_id, user_id, ip_address) 
  DO UPDATE SET 
    is_active = true,
    left_at = NULL,
    joined_at = now()
  RETURNING id INTO v_listener_id;
  
  RETURN v_listener_id;
END;
$function$;

CREATE OR REPLACE FUNCTION public.unregister_listener(p_session_id uuid, p_user_id uuid DEFAULT NULL::uuid, p_ip_address text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  UPDATE live_session_listeners
  SET is_active = false,
      left_at = now()
  WHERE session_id = p_session_id
    AND (user_id = p_user_id OR (user_id IS NULL AND ip_address = p_ip_address));
END;
$function$;
-- Add search_path to handle_guest_approval function to prevent schema poisoning attacks
CREATE OR REPLACE FUNCTION handle_guest_approval()
RETURNS TRIGGER AS $$
BEGIN
  -- Only proceed if status changed from pending to approved
  IF NEW.request_status = 'approved' AND OLD.request_status = 'pending' THEN
    -- Insert guest into meeting_participants table
    INSERT INTO meeting_participants (
      meeting_id,
      user_id,
      guest_name,
      guest_email,
      role,
      joined_at,
      is_active,
      connection_quality,
      audio_enabled,
      video_enabled
    )
    VALUES (
      NEW.meeting_id,
      NEW.user_id,
      NEW.guest_name,
      NEW.guest_email,
      'guest',
      NOW(),
      true,
      'good',
      true,
      true
    )
    ON CONFLICT (meeting_id, COALESCE(user_id, '00000000-0000-0000-0000-000000000000'::uuid), COALESCE(guest_email, ''))
    DO NOTHING;
  END IF;

  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path TO 'public';
-- Fix critical RLS bug: Allow company members and strategists to UPDATE applications
DROP POLICY IF EXISTS "Company members can update applications" ON applications;

CREATE POLICY "Company members can update applications"
ON applications
FOR UPDATE
TO public
USING (
  -- Allow admins, partners, strategists to update
  has_role(auth.uid(), 'admin') 
  OR has_role(auth.uid(), 'partner')
  OR has_role(auth.uid(), 'strategist')
  -- Allow company members to update applications for their company's jobs
  OR EXISTS (
    SELECT 1 FROM jobs j
    JOIN company_members cm ON cm.company_id = j.company_id
    WHERE j.id = applications.job_id
      AND cm.user_id = auth.uid()
      AND cm.is_active = true
  )
  -- Allow users to update their own applications
  OR (auth.uid() = user_id AND user_id IS NOT NULL)
)
WITH CHECK (
  -- Same permissions for WITH CHECK
  has_role(auth.uid(), 'admin') 
  OR has_role(auth.uid(), 'partner')
  OR has_role(auth.uid(), 'strategist')
  OR EXISTS (
    SELECT 1 FROM jobs j
    JOIN company_members cm ON cm.company_id = j.company_id
    WHERE j.id = applications.job_id
      AND cm.user_id = auth.uid()
      AND cm.is_active = true
  )
  OR (auth.uid() = user_id AND user_id IS NOT NULL)
);

