CREATE OR REPLACE FUNCTION public.update_candidate_profile()
RETURNS trigger
LANGUAGE plpgsql
SET search_path = public
AS $function$
BEGIN
  INSERT INTO candidate_assessment_profiles (user_id)
  VALUES (NEW.user_id)
