DROP TRIGGER IF EXISTS update_stats_on_enrollment ON learner_progress;
CREATE TRIGGER update_stats_on_enrollment
  AFTER INSERT ON learner_progress
  FOR EACH ROW EXECUTE FUNCTION update_course_stats();

