-- Check if user has active subscription
CREATE OR REPLACE FUNCTION public.has_active_subscription(check_user_id UUID, check_user_type TEXT DEFAULT NULL)
RETURNS BOOLEAN
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  RETURN EXISTS (
    SELECT 1 
    FROM public.subscriptions s
    JOIN public.subscription_plans sp ON s.plan_id = sp.id
    WHERE s.user_id = check_user_id
      AND s.status = 'active'
      AND s.current_period_end > now()
      AND (check_user_type IS NULL OR sp.user_type = check_user_type)
  );
END;
$$;

-- Get user's current subscription plan
CREATE OR REPLACE FUNCTION public.get_user_subscription_plan(check_user_id UUID)
RETURNS TABLE(
  plan_name TEXT,
  tier TEXT,
  user_type TEXT,
  status TEXT,
  period_end TIMESTAMPTZ
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  RETURN QUERY
  SELECT 
    sp.name,
    sp.tier,
    sp.user_type,
    s.status,
    s.current_period_end
  FROM public.subscriptions s
  JOIN public.subscription_plans sp ON s.plan_id = sp.id
  WHERE s.user_id = check_user_id
    AND s.status IN ('active', 'trialing')
  ORDER BY s.current_period_end DESC
  LIMIT 1;
END;
$$;-- =============================================
