        WITH CHECK (user_id = auth.uid());
      
      CREATE POLICY "Users can update their own skill assessments"
        ON public.skill_assessments
        FOR UPDATE
        TO authenticated
        USING (user_id = auth.uid());
    END IF;
  END IF;
END $$;

