-- Create a function to calculate cosine similarity (helper for queries)
CREATE OR REPLACE FUNCTION cosine_similarity(a vector, b vector)
RETURNS float
LANGUAGE plpgsql IMMUTABLE STRICT PARALLEL SAFE
AS $$
BEGIN
  RETURN 1 - (a <=> b);
END;
$$;

COMMENT ON COLUMN candidate_profiles.profile_embedding IS 'OpenAI text-embedding-3-small (1536 dimensions) of candidate profile text';
COMMENT ON COLUMN jobs.job_embedding IS 'OpenAI text-embedding-3-small (1536 dimensions) of job description';
COMMENT ON COLUMN knowledge_base_articles.content_embedding IS 'OpenAI text-embedding-3-small (1536 dimensions) of article content';
COMMENT ON COLUMN company_interactions.interaction_embedding IS 'OpenAI text-embedding-3-small (1536 dimensions) of interaction context';-- Fix function search_path security issue
CREATE OR REPLACE FUNCTION cosine_similarity(a vector, b vector)
RETURNS float
LANGUAGE plpgsql IMMUTABLE STRICT PARALLEL SAFE
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  RETURN 1 - (a <=> b);
END;
$$;-- Create RPC function for efficient semantic search
CREATE OR REPLACE FUNCTION semantic_search_candidates(
  query_embedding vector(1536),
  match_threshold float DEFAULT 0.7,
  match_count int DEFAULT 10
)
RETURNS TABLE (
  id uuid,
  user_id uuid,
  full_name text,
  current_title text,
  current_company text,
  bio text,
  location text,
  similarity_score float
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  RETURN QUERY
  SELECT 
    cp.id,
    cp.user_id,
    cp.full_name,
    cp.current_title,
    cp.current_company,
    cp.bio,
    cp.location,
    1 - (cp.profile_embedding <=> query_embedding) as similarity_score
  FROM candidate_profiles cp
  WHERE cp.profile_embedding IS NOT NULL
    AND 1 - (cp.profile_embedding <=> query_embedding) >= match_threshold
  ORDER BY cp.profile_embedding <=> query_embedding
  LIMIT match_count;
END;
$$;

-- Create RPC function for job semantic search
CREATE OR REPLACE FUNCTION semantic_search_jobs(
  query_embedding vector(1536),
  match_threshold float DEFAULT 0.7,
  match_count int DEFAULT 10
)
RETURNS TABLE (
  id uuid,
  title text,
  department text,
  location text,
  description text,
  requirements text,
  similarity_score float
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  RETURN QUERY
  SELECT 
    j.id,
    j.title,
    j.department,
    j.location,
    j.description,
    j.requirements,
    1 - (j.job_embedding <=> query_embedding) as similarity_score
  FROM jobs j
  WHERE j.job_embedding IS NOT NULL
    AND 1 - (j.job_embedding <=> query_embedding) >= match_threshold
  ORDER BY j.job_embedding <=> query_embedding
  LIMIT match_count;
END;
$$;

-- Create RPC function for knowledge base semantic search
CREATE OR REPLACE FUNCTION semantic_search_knowledge(
  query_embedding vector(1536),
  match_threshold float DEFAULT 0.7,
  match_count int DEFAULT 10
)
RETURNS TABLE (
  id uuid,
  title text,
  content text,
  category text,
  tags text[],
  similarity_score float
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  RETURN QUERY
  SELECT 
    k.id,
    k.title,
    k.content,
    k.category,
    k.tags,
    1 - (k.content_embedding <=> query_embedding) as similarity_score
  FROM knowledge_base_articles k
  WHERE k.content_embedding IS NOT NULL
    AND 1 - (k.content_embedding <=> query_embedding) >= match_threshold
  ORDER BY k.content_embedding <=> query_embedding
  LIMIT match_count;
END;
$$;

-- Create function to get embedding statistics
CREATE OR REPLACE FUNCTION get_embedding_stats()
RETURNS TABLE (
  entity_type text,
  total_records bigint,
  with_embeddings bigint,
  percentage numeric
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  RETURN QUERY
  SELECT 
    'candidates' as entity_type,
    COUNT(*) as total_records,
    COUNT(profile_embedding) as with_embeddings,
    ROUND((COUNT(profile_embedding)::numeric / NULLIF(COUNT(*), 0) * 100), 2) as percentage
  FROM candidate_profiles
  UNION ALL
  SELECT 
    'jobs' as entity_type,
    COUNT(*) as total_records,
    COUNT(job_embedding) as with_embeddings,
    ROUND((COUNT(job_embedding)::numeric / NULLIF(COUNT(*), 0) * 100), 2) as percentage
  FROM jobs
  UNION ALL
  SELECT 
    'knowledge_articles' as entity_type,
    COUNT(*) as total_records,
    COUNT(content_embedding) as with_embeddings,
    ROUND((COUNT(content_embedding)::numeric / NULLIF(COUNT(*), 0) * 100), 2) as percentage
  FROM knowledge_base_articles
  UNION ALL
  SELECT 
    'interactions' as entity_type,
    COUNT(*) as total_records,
    COUNT(interaction_embedding) as with_embeddings,
    ROUND((COUNT(interaction_embedding)::numeric / NULLIF(COUNT(*), 0) * 100), 2) as percentage
  FROM company_interactions;
END;
$$;-- Phase 2: Complete ML Training Infrastructure

-- Create ml_models table if not exists
CREATE TABLE IF NOT EXISTS ml_models (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  version INTEGER NOT NULL UNIQUE,
  model_type TEXT NOT NULL CHECK (model_type IN ('xgboost', 'lightgbm', 'neural_net', 'ensemble', 'baseline')),
  model_storage_path TEXT,
  model_weights JSONB,
  training_config JSONB,
  metrics JSONB,
  feature_importance JSONB,
  training_data_count INTEGER,
  training_start_time TIMESTAMPTZ,
  training_end_time TIMESTAMPTZ,
  status TEXT DEFAULT 'training' CHECK (status IN ('training', 'testing', 'active', 'retired', 'failed')),
  notes TEXT,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- Create ml_predictions table if not exists
CREATE TABLE IF NOT EXISTS ml_predictions (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  model_version INTEGER NOT NULL,
  candidate_id UUID NOT NULL REFERENCES candidate_profiles(id) ON DELETE CASCADE,
  job_id UUID NOT NULL REFERENCES jobs(id) ON DELETE CASCADE,
  prediction_score DECIMAL(5,4) NOT NULL,
  interview_probability DECIMAL(5,4),
  predicted_time_to_hire_days INTEGER,
  rank_position INTEGER,
  features_used JSONB,
  shap_values JSONB,
  ab_test_id UUID,
  ab_test_variant TEXT CHECK (ab_test_variant IN ('model_a', 'model_b', 'control')),
  actual_outcome TEXT CHECK (actual_outcome IN ('hired', 'interviewed', 'rejected', 'pending')),
  actual_outcome_updated_at TIMESTAMPTZ,
  created_at TIMESTAMPTZ DEFAULT now()
);

-- Create ml_training_data table
CREATE TABLE IF NOT EXISTS ml_training_data (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  candidate_id UUID NOT NULL,
  job_id UUID NOT NULL,
  application_id UUID,
  company_id UUID,
  features JSONB NOT NULL,
  semantic_similarity_score DECIMAL(5,4),
  label_hired BOOLEAN NOT NULL DEFAULT false,
  label_interviewed BOOLEAN NOT NULL DEFAULT false,
  label_rejected BOOLEAN NOT NULL DEFAULT false,
  time_to_hire_days INTEGER,
  time_to_interview_days INTEGER,
  rejection_stage TEXT,
  match_score_at_time DECIMAL(5,4),
  strategist_feedback TEXT,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- Create ml_training_runs table
CREATE TABLE IF NOT EXISTS ml_training_runs (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  model_version INTEGER NOT NULL,
  training_start_time TIMESTAMPTZ NOT NULL DEFAULT now(),
  training_end_time TIMESTAMPTZ,
  training_samples_count INTEGER,
  validation_samples_count INTEGER,
  hyperparameters JSONB,
  metrics JSONB,
  feature_importance JSONB,
  status TEXT DEFAULT 'running' CHECK (status IN ('running', 'completed', 'failed')),
  error_message TEXT,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- Create ml_ab_tests table if not exists
CREATE TABLE IF NOT EXISTS ml_ab_tests (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  test_name TEXT NOT NULL,
  model_a_version INTEGER NOT NULL,
  model_b_version INTEGER NOT NULL,
  traffic_split DECIMAL(3,2) NOT NULL DEFAULT 0.5,
  target_metric TEXT NOT NULL,
  hypothesis TEXT,
  metrics_a JSONB,
  metrics_b JSONB,
  statistical_significance DECIMAL(5,4),
  winner TEXT CHECK (winner IN ('model_a', 'model_b', 'no_difference', 'pending')),
  sample_size_a INTEGER DEFAULT 0,
  sample_size_b INTEGER DEFAULT 0,
  status TEXT DEFAULT 'running' CHECK (status IN ('running', 'completed', 'stopped')),
  started_at TIMESTAMPTZ DEFAULT now(),
  ended_at TIMESTAMPTZ
);

-- Create ml_feedback table if not exists
CREATE TABLE IF NOT EXISTS ml_feedback (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  prediction_id UUID NOT NULL REFERENCES ml_predictions(id) ON DELETE CASCADE,
  user_id UUID NOT NULL,
  user_role TEXT NOT NULL CHECK (user_role IN ('candidate', 'strategist', 'partner')),
  feedback_type TEXT NOT NULL CHECK (feedback_type IN ('boost', 'block', 'great_match', 'not_relevant', 'wrong_skills', 'wrong_culture', 'wrong_salary')),
  feedback_score INTEGER CHECK (feedback_score BETWEEN 1 AND 5),
  feedback_text TEXT,
  metadata JSONB,
  created_at TIMESTAMPTZ DEFAULT now()
);

