-- Auto-calculate final_value on sales_proposals
CREATE OR REPLACE FUNCTION public.calculate_proposal_final_value()
RETURNS TRIGGER AS $$
BEGIN
  NEW.final_value = NEW.proposal_value * (1 - COALESCE(NEW.discount_percentage, 0) / 100);
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = public;

CREATE TRIGGER calculate_proposal_final_value_trigger
  BEFORE INSERT OR UPDATE ON public.sales_proposals
  FOR EACH ROW EXECUTE FUNCTION public.calculate_proposal_final_value();

-- Auto-populate sales_conversations from company_interactions
CREATE OR REPLACE FUNCTION public.auto_create_sales_conversation()
RETURNS TRIGGER AS $$
BEGIN
  IF NEW.interaction_type IN ('call', 'email', 'meeting') THEN
    INSERT INTO public.sales_conversations (
      company_id,
      company_interaction_id,
      channel,
      direction,
      first_message_at,
      last_message_at,
      owner_id,
      sentiment_trend
    ) VALUES (
      NEW.company_id,
      NEW.id,
      CASE WHEN NEW.interaction_type = 'call' THEN 'call' ELSE 'email' END,
      NEW.direction,
      COALESCE(NEW.interaction_date, NOW()),
      COALESCE(NEW.interaction_date, NOW()),
      NEW.created_by,
      NEW.sentiment_score
    )
    ON CONFLICT DO NOTHING;
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = public;

CREATE TRIGGER auto_create_sales_conversation_trigger
  AFTER INSERT ON public.company_interactions
  FOR EACH ROW EXECUTE FUNCTION public.auto_create_sales_conversation();

-- Detect slipping deals function
CREATE OR REPLACE FUNCTION public.detect_slipping_deals()
RETURNS void AS $$
BEGIN
  UPDATE public.sales_forecasts sf
  SET 
    is_slipping = true,
    slip_days = EXTRACT(DAY FROM NOW() - last_activity_date)::INTEGER
  WHERE last_activity_date < NOW() - INTERVAL '14 days'
    AND is_slipping = false;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = public;-- Add scheduled_send_at column to booking_reminders for event-driven scheduling
ALTER TABLE booking_reminders 
ADD COLUMN IF NOT EXISTS scheduled_send_at TIMESTAMPTZ;

-- Backfill existing reminders with calculated send times
UPDATE booking_reminders br
SET scheduled_send_at = (
  SELECT b.scheduled_start - (br.send_before_minutes || ' minutes')::INTERVAL
  FROM bookings b WHERE b.id = br.booking_id
)
WHERE scheduled_send_at IS NULL;

-- Create index for efficient queries on pending reminders
CREATE INDEX IF NOT EXISTS idx_booking_reminders_scheduled_send 
ON booking_reminders(scheduled_send_at) WHERE status = 'pending';

-- Mark past reminders as failed (cleanup stale data - missed send window)
UPDATE booking_reminders br
SET status = 'failed'
WHERE status = 'pending'
AND scheduled_send_at < NOW();

-- Function to unschedule a booking reminder cron job
CREATE OR REPLACE FUNCTION unschedule_booking_reminder(p_reminder_id UUID)
RETURNS VOID AS $$
DECLARE
  job_name TEXT;
BEGIN
  job_name := 'reminder_' || p_reminder_id::TEXT;
  
  -- Try to unschedule the job (ignore if it doesn't exist)
  BEGIN
    PERFORM cron.unschedule(job_name);
  EXCEPTION WHEN OTHERS THEN
    -- Job doesn't exist or already unscheduled - that's fine
    NULL;
  END;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = public;-- Fix security issues identified in security scan

-- 1. Fix the refresh_analytics_views function to include search_path
CREATE OR REPLACE FUNCTION public.refresh_analytics_views()
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  REFRESH MATERIALIZED VIEW CONCURRENTLY public.mv_daily_user_segments;
  REFRESH MATERIALIZED VIEW CONCURRENTLY public.mv_feature_usage_summary;
END;
$$;

-- 2. Recreate error_analytics_summary view with security_invoker=true
DROP VIEW IF EXISTS public.error_analytics_summary;

CREATE VIEW public.error_analytics_summary 
WITH (security_invoker = true)
AS
SELECT 
  date_trunc('day'::text, created_at) AS date,
  severity,
  error_type,
  count(*) AS error_count,
  count(*) FILTER (WHERE resolved = true) AS resolved_count,
  avg(EXTRACT(epoch FROM resolved_at - created_at) / 3600::numeric) FILTER (WHERE resolved = true) AS avg_resolution_hours
FROM error_logs
WHERE created_at > (now() - '30 days'::interval)
GROUP BY (date_trunc('day'::text, created_at)), severity, error_type
ORDER BY (date_trunc('day'::text, created_at)) DESC;

-- Grant appropriate permissions on the view
GRANT SELECT ON public.error_analytics_summary TO authenticated;-- Fix Deal Pipeline database functions - drop and recreate with correct signatures

-- Drop the function first since return type is changing
DROP FUNCTION IF EXISTS public.get_pipeline_candidate_stats(uuid);

-- Recreate get_pipeline_candidate_stats with correct column references
CREATE OR REPLACE FUNCTION public.get_pipeline_candidate_stats(p_job_id uuid)
RETURNS TABLE(
  total_candidates bigint,
  avg_experience_years numeric,
  avg_current_salary numeric,
  avg_desired_salary numeric,
  skill_match_rate numeric
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  RETURN QUERY
  SELECT 
    COUNT(DISTINCT a.candidate_id)::bigint as total_candidates,
    COALESCE(AVG(cp.years_of_experience), 0)::numeric as avg_experience_years,
    COALESCE(AVG(cp.current_salary_min), 0)::numeric as avg_current_salary,
    COALESCE(AVG(cp.desired_salary_min), 0)::numeric as avg_desired_salary,
    COALESCE(AVG(a.match_score), 0)::numeric as skill_match_rate
  FROM applications a
  LEFT JOIN candidate_profiles cp ON a.candidate_id = cp.id
  WHERE a.job_id = p_job_id
    AND a.status NOT IN ('rejected', 'withdrawn');
END;
$$;

