-- Function to ensure only one running timer per user
CREATE OR REPLACE FUNCTION ensure_single_running_timer()
RETURNS TRIGGER AS $$
BEGIN
  IF NEW.is_running = true THEN
    -- Stop any other running timers for this user
    UPDATE public.time_entries
    SET 
      is_running = false,
      end_time = now(),
      duration_seconds = EXTRACT(EPOCH FROM (now() - start_time))::INTEGER,
      updated_at = now()
    WHERE user_id = NEW.user_id 
      AND id != NEW.id 
      AND is_running = true;
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = public;

CREATE TRIGGER ensure_single_timer_trigger
  BEFORE INSERT OR UPDATE ON public.time_entries
  FOR EACH ROW
  EXECUTE FUNCTION ensure_single_running_timer();

-- Function to auto-update updated_at
CREATE OR REPLACE FUNCTION update_time_entries_updated_at()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SET search_path = public;

CREATE TRIGGER time_entries_updated_at
  BEFORE UPDATE ON public.time_entries
  FOR EACH ROW
  EXECUTE FUNCTION update_time_entries_updated_at();
-- Activity samples for granular tracking (stores per-minute activity data)
CREATE TABLE public.activity_samples (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  time_entry_id UUID REFERENCES public.time_entries(id) ON DELETE CASCADE NOT NULL,
  user_id UUID NOT NULL,
  timestamp TIMESTAMPTZ NOT NULL DEFAULT now(),
  mouse_events INTEGER NOT NULL DEFAULT 0,
  keyboard_events INTEGER NOT NULL DEFAULT 0,
  activity_percentage INTEGER NOT NULL DEFAULT 0 CHECK (activity_percentage >= 0 AND activity_percentage <= 100),
  created_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

