-- 8. Fix stuck translation jobs
UPDATE translation_generation_jobs 
SET status = 'failed', 
    error_message = 'Job timed out or was interrupted',
    completed_at = NOW()
WHERE status = 'running' 
  AND (started_at < NOW() - INTERVAL '1 hour' OR started_at IS NULL);-- Clean up stuck job
UPDATE translation_generation_jobs 
SET status = 'failed', 
    error_message = 'System cleanup - job timed out',
    completed_at = NOW()
WHERE status = 'running' 
AND started_at < NOW() - INTERVAL '30 minutes';

-- Create brand_terms table for protected terms
CREATE TABLE IF NOT EXISTS public.brand_terms (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  term TEXT NOT NULL,
  description TEXT,
  never_translate BOOLEAN DEFAULT true,
  translations JSONB DEFAULT '{}',
