-- =============================================
-- UPDATE TRIGGERS
-- =============================================
CREATE OR REPLACE FUNCTION public.update_freelance_marketplace_updated_at()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = public;

CREATE TRIGGER update_freelance_profiles_updated_at
  BEFORE UPDATE ON public.freelance_profiles
  FOR EACH ROW EXECUTE FUNCTION public.update_freelance_marketplace_updated_at();

CREATE TRIGGER update_marketplace_projects_updated_at
  BEFORE UPDATE ON public.marketplace_projects
  FOR EACH ROW EXECUTE FUNCTION public.update_freelance_marketplace_updated_at();

CREATE TRIGGER update_project_proposals_updated_at
  BEFORE UPDATE ON public.project_proposals
  FOR EACH ROW EXECUTE FUNCTION public.update_freelance_marketplace_updated_at();

CREATE TRIGGER update_freelance_contracts_updated_at
  BEFORE UPDATE ON public.freelance_contracts
  FOR EACH ROW EXECUTE FUNCTION public.update_freelance_marketplace_updated_at();

CREATE TRIGGER update_project_milestones_updated_at
  BEFORE UPDATE ON public.project_milestones
  FOR EACH ROW EXECUTE FUNCTION public.update_freelance_marketplace_updated_at();

CREATE TRIGGER update_project_reviews_updated_at
  BEFORE UPDATE ON public.project_reviews
  FOR EACH ROW EXECUTE FUNCTION public.update_freelance_marketplace_updated_at();

CREATE TRIGGER update_project_disputes_updated_at
  BEFORE UPDATE ON public.project_disputes
  FOR EACH ROW EXECUTE FUNCTION public.update_freelance_marketplace_updated_at();

CREATE TRIGGER update_freelancer_gigs_updated_at
  BEFORE UPDATE ON public.freelancer_gigs
  FOR EACH ROW EXECUTE FUNCTION public.update_freelance_marketplace_updated_at();

CREATE TRIGGER update_gig_orders_updated_at
  BEFORE UPDATE ON public.gig_orders
  FOR EACH ROW EXECUTE FUNCTION public.update_freelance_marketplace_updated_at();-- Create brand assets cache table
CREATE TABLE IF NOT EXISTS public.brand_assets_cache (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  domain TEXT UNIQUE NOT NULL,
  logo_url TEXT,
  icon_url TEXT,
  brand_name TEXT,
  primary_color TEXT,
  colors JSONB,
  fetched_at TIMESTAMPTZ DEFAULT now(),
  expires_at TIMESTAMPTZ DEFAULT now() + INTERVAL '30 days',
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- Create index for domain lookups
CREATE INDEX IF NOT EXISTS idx_brand_assets_cache_domain ON public.brand_assets_cache(domain);

-- Create index for expiry cleanup
CREATE INDEX IF NOT EXISTS idx_brand_assets_cache_expires ON public.brand_assets_cache(expires_at);

-- Enable RLS
ALTER TABLE public.brand_assets_cache ENABLE ROW LEVEL SECURITY;

-- Allow anyone to read cached assets
CREATE POLICY "Anyone can read brand assets cache"
ON public.brand_assets_cache
FOR SELECT
USING (true);

-- Only service role can insert/update (edge function uses service role)
CREATE POLICY "Service role can manage brand assets cache"
ON public.brand_assets_cache
FOR ALL TO service_role USING (true)
WITH CHECK (true);

-- Add updated_at trigger
CREATE OR REPLACE FUNCTION public.update_brand_assets_cache_updated_at()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS update_brand_assets_cache_updated_at ON public.brand_assets_cache;
CREATE TRIGGER update_brand_assets_cache_updated_at
  BEFORE UPDATE ON public.brand_assets_cache
  FOR EACH ROW
  EXECUTE FUNCTION public.update_brand_assets_cache_updated_at();-- Create workspace_pages table for Notion-like pages
CREATE TABLE public.workspace_pages (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  user_id UUID NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  parent_page_id UUID REFERENCES public.workspace_pages(id) ON DELETE CASCADE,
  title TEXT NOT NULL DEFAULT 'Untitled',
  icon_emoji TEXT,
  icon_url TEXT,
  cover_url TEXT,
  content JSONB DEFAULT '[]'::jsonb,
  sort_order INTEGER DEFAULT 0,
  is_template BOOLEAN DEFAULT false,
  is_favorite BOOLEAN DEFAULT false,
  is_archived BOOLEAN DEFAULT false,
  visibility TEXT DEFAULT 'private' CHECK (visibility IN ('private', 'shared', 'public')),
  last_edited_by UUID REFERENCES auth.users(id),
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- Create page_templates table for quick page creation
CREATE TABLE public.page_templates (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name TEXT NOT NULL,
  description TEXT,
  icon TEXT,
  content JSONB DEFAULT '[]'::jsonb,
  category TEXT,
  is_system BOOLEAN DEFAULT false,
  created_by UUID REFERENCES auth.users(id),
  created_at TIMESTAMPTZ DEFAULT now()
);

-- Create page_permissions table for sharing
CREATE TABLE public.page_permissions (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  page_id UUID NOT NULL REFERENCES public.workspace_pages(id) ON DELETE CASCADE,
  user_id UUID REFERENCES auth.users(id),
  email TEXT,
  permission_level TEXT DEFAULT 'view' CHECK (permission_level IN ('view', 'comment', 'edit', 'full')),
  created_at TIMESTAMPTZ DEFAULT now()
);

-- Create page_visits table for recent pages
