-- Function to update is_overdue flag
CREATE OR REPLACE FUNCTION update_task_overdue_status()
RETURNS void
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  UPDATE unified_tasks
  SET is_overdue = true
  WHERE due_date < CURRENT_DATE
    AND status NOT IN ('completed', 'on_hold')
    AND is_overdue = false;
    
  UPDATE unified_tasks
  SET is_overdue = false
  WHERE (due_date >= CURRENT_DATE OR status IN ('completed', 'on_hold'))
    AND is_overdue = true;
END;
$$;-- Add project_id to unified_tasks if it doesn't exist
DO $$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM information_schema.columns WHERE table_name = 'unified_tasks' AND column_name = 'project_id') THEN
        ALTER TABLE "public"."unified_tasks" ADD COLUMN "project_id" uuid REFERENCES "public"."marketplace_projects"("id") ON DELETE SET NULL;
    END IF;
END $$;

