-- 2.1 Create or replace the trigger function for placement fee on hire
CREATE OR REPLACE FUNCTION create_placement_fee_on_hire_v2()
RETURNS TRIGGER AS $$
DECLARE
  v_job RECORD;
  v_fee_percentage NUMERIC;
  v_fee_amount NUMERIC;
  v_base_salary NUMERIC;
  v_existing_fee UUID;
BEGIN
  -- Only process when status changes to 'hired'
  IF NEW.status = 'hired' AND (OLD.status IS NULL OR OLD.status != 'hired') THEN
    
    -- Check if placement fee already exists
    SELECT id INTO v_existing_fee FROM placement_fees WHERE application_id = NEW.id;
    IF v_existing_fee IS NOT NULL THEN
      RETURN NEW;
    END IF;
    
    -- Get job and company details
    SELECT 
      j.id as job_id,
      j.title,
      j.salary_min,
      j.salary_max,
      j.company_id,
      c.name as company_name,
      COALESCE(c.default_fee_percentage, 20) as company_fee_pct
    INTO v_job
    FROM jobs j
    LEFT JOIN companies c ON c.id = j.company_id
    WHERE j.id = NEW.job_id;
    
    IF v_job IS NULL THEN
      RETURN NEW;
    END IF;
    
    -- Calculate fee
    v_base_salary := COALESCE(v_job.salary_max, v_job.salary_min, 75000);
    v_fee_percentage := v_job.company_fee_pct;
    v_fee_amount := v_base_salary * (v_fee_percentage / 100);
    
    -- Insert placement fee
    INSERT INTO placement_fees (
      application_id, 
      job_id, 
      candidate_id, 
      partner_company_id,
      fee_percentage, 
      candidate_salary, 
      fee_amount, 
      currency_code,
      status, 
      hired_date, 
      created_by,
      notes
    )
    VALUES (
      NEW.id, 
      NEW.job_id, 
      NEW.candidate_id, 
      v_job.company_id,
      v_fee_percentage, 
      v_base_salary, 
      v_fee_amount, 
      'EUR',
      'pending', 
      NOW(), 
      COALESCE(NEW.sourced_by, NEW.user_id),
      'Auto-generated on hire status change'
    );
    
  END IF;
  
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = public;

-- 2.2 Drop existing trigger if exists and create new one
DROP TRIGGER IF EXISTS trg_create_placement_fee_on_hire_v2 ON applications;
CREATE TRIGGER trg_create_placement_fee_on_hire_v2
  AFTER UPDATE ON applications
  FOR EACH ROW
  EXECUTE FUNCTION create_placement_fee_on_hire_v2();

-- Also handle INSERT case where status is already 'hired'
DROP TRIGGER IF EXISTS trg_create_placement_fee_on_hire_insert ON applications;
CREATE TRIGGER trg_create_placement_fee_on_hire_insert
  AFTER INSERT ON applications
  FOR EACH ROW
  WHEN (NEW.status = 'hired')
  EXECUTE FUNCTION create_placement_fee_on_hire_v2();-- Phase 3: Automated Commission Calculation

CREATE OR REPLACE FUNCTION calculate_commissions_on_placement_fee()
RETURNS TRIGGER AS $$
DECLARE
  v_application RECORD;
  v_recruiter_employee RECORD;
  v_strategist_assignment RECORD;
  v_commission_rate NUMERIC;
  v_commission_amount NUMERIC;
  v_strategist_rate NUMERIC;
  v_strategist_amount NUMERIC;
BEGIN
  -- Get application details
  SELECT 
    a.*,
    cp.full_name as candidate_name,
    j.title as job_title,
    c.name as company_name
  INTO v_application
  FROM applications a
  LEFT JOIN candidate_profiles cp ON cp.id = a.candidate_id
  LEFT JOIN jobs j ON j.id = a.job_id
  LEFT JOIN companies c ON c.id = j.company_id
  WHERE a.id = NEW.application_id;
  
  -- Get recruiter employee profile with commission tier
  SELECT 
    ep.*,
    COALESCE(ct.percentage, ep.commission_percentage, 10) as effective_rate
  INTO v_recruiter_employee
  FROM employee_profiles ep
  LEFT JOIN commission_tiers ct ON ct.id = ep.commission_tier_id AND ct.is_active = true
  WHERE ep.user_id = COALESCE(NEW.created_by, v_application.sourced_by, v_application.user_id);
  
  IF v_recruiter_employee.id IS NOT NULL THEN
    v_commission_rate := v_recruiter_employee.effective_rate;
    v_commission_amount := NEW.fee_amount * (v_commission_rate / 100);
    
    -- Create recruiter commission (avoid duplicates)
    INSERT INTO employee_commissions (
      employee_id, 
      source_type, 
      source_id, 
      placement_fee_id,
      gross_amount, 
      commission_rate, 
      placement_fee_base,
      candidate_name, 
      company_name, 
      job_title, 
      commission_type,
      split_percentage,
      status, 
      period_date
    )
    SELECT
      v_recruiter_employee.id, 
      'placement_fee', 
      NEW.id, 
      NEW.id,
      v_commission_amount, 
      v_commission_rate, 
      NEW.fee_amount,
      v_application.candidate_name, 
      v_application.company_name, 
      v_application.job_title, 
      'placement',
      100,
      'pending', 
      CURRENT_DATE
    WHERE NOT EXISTS (
      SELECT 1 FROM employee_commissions 
      WHERE placement_fee_id = NEW.id 
        AND employee_id = v_recruiter_employee.id 
        AND commission_type = 'placement'
    );
  END IF;
  
  -- Check for strategist assignment and create split commission
  SELECT 
    csa.*,
    ep.id as strategist_employee_id,
    COALESCE(ct.percentage, ep.commission_percentage, 10) as strategist_tier_rate
  INTO v_strategist_assignment
  FROM company_strategist_assignments csa
  JOIN employee_profiles ep ON ep.user_id = csa.strategist_id
  LEFT JOIN commission_tiers ct ON ct.id = ep.commission_tier_id AND ct.is_active = true
  WHERE csa.company_id = NEW.partner_company_id
    AND csa.is_active = true
    AND csa.strategist_id != COALESCE(NEW.created_by, v_application.sourced_by);
  
  IF v_strategist_assignment.strategist_employee_id IS NOT NULL THEN
    -- Strategist gets 20% of the base commission rate
    v_strategist_rate := v_strategist_assignment.strategist_tier_rate * 0.2;
    v_strategist_amount := NEW.fee_amount * (v_strategist_rate / 100);
    
    INSERT INTO employee_commissions (
      employee_id, 
      source_type, 
      source_id, 
      placement_fee_id,
      gross_amount, 
      commission_rate, 
      placement_fee_base,
      candidate_name, 
      company_name, 
      job_title, 
      commission_type,
      split_percentage, 
      status, 
      period_date
    )
    SELECT
      v_strategist_assignment.strategist_employee_id, 
      'placement_fee', 
      NEW.id, 
      NEW.id,
      v_strategist_amount, 
      v_strategist_rate, 
      NEW.fee_amount,
      v_application.candidate_name, 
      v_application.company_name, 
      v_application.job_title, 
      'strategist_split',
      20, 
      'pending', 
      CURRENT_DATE
    WHERE NOT EXISTS (
      SELECT 1 FROM employee_commissions 
      WHERE placement_fee_id = NEW.id 
        AND employee_id = v_strategist_assignment.strategist_employee_id 
        AND commission_type = 'strategist_split'
    );
  END IF;
  
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = public;

-- Create Commission Trigger on placement_fees
DROP TRIGGER IF EXISTS trg_calculate_commissions ON placement_fees;
CREATE TRIGGER trg_calculate_commissions
  AFTER INSERT ON placement_fees
  FOR EACH ROW
  EXECUTE FUNCTION calculate_commissions_on_placement_fee();-- Phase 4: Referral Payout Automation

CREATE OR REPLACE FUNCTION create_referral_payout_on_hire()
RETURNS TRIGGER AS $$
DECLARE
  v_referral_earning RECORD;
  v_config RECORD;
  v_payout_amount NUMERIC;
BEGIN
  IF NEW.status = 'hired' AND (OLD.status IS NULL OR OLD.status != 'hired') THEN
    
    -- Get referral earnings for this application
    SELECT 
      re.*,
      p.full_name as referrer_name
    INTO v_referral_earning
    FROM referral_earnings re
    LEFT JOIN profiles p ON p.id = re.referrer_id
    WHERE re.application_id = NEW.id
      AND re.status IN ('pending', 'projected', 'qualified');
    
    IF v_referral_earning.id IS NOT NULL THEN
      -- Get referral config for default amounts
      SELECT * INTO v_config
      FROM referral_config
      WHERE is_active = true
      ORDER BY created_at DESC
      LIMIT 1;
      
      v_payout_amount := COALESCE(v_referral_earning.amount, v_config.bonus_amount_euros, 500);
      
      -- Create referral payout (avoid duplicates)
      INSERT INTO referral_payouts (
        referrer_user_id, 
        candidate_id, 
        application_id,
        payout_amount, 
        currency_code, 
        status, 
        notes
      )
      SELECT 
        v_referral_earning.referrer_id, 
        NEW.candidate_id, 
        NEW.id,
        v_payout_amount, 
        'EUR', 
        'pending', 
        'Auto-created on hire - referral from ' || COALESCE(v_referral_earning.referrer_name, 'Unknown')
      WHERE NOT EXISTS (
        SELECT 1 FROM referral_payouts 
        WHERE application_id = NEW.id 
          AND referrer_user_id = v_referral_earning.referrer_id
      );
      
      -- Update referral earning status to realized
      UPDATE referral_earnings
      SET status = 'realized',
          payment_status = 'pending',
          updated_at = NOW()
      WHERE id = v_referral_earning.id;
    END IF;
  END IF;
  
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = public;

-- Create Referral Trigger
DROP TRIGGER IF EXISTS trg_create_referral_payout ON applications;
CREATE TRIGGER trg_create_referral_payout
  AFTER UPDATE ON applications
  FOR EACH ROW
  EXECUTE FUNCTION create_referral_payout_on_hire();

-- Also for INSERT with hired status
DROP TRIGGER IF EXISTS trg_create_referral_payout_insert ON applications;
CREATE TRIGGER trg_create_referral_payout_insert
  AFTER INSERT ON applications
  FOR EACH ROW
  WHEN (NEW.status = 'hired')
  EXECUTE FUNCTION create_referral_payout_on_hire();-- Phase 8: Add cash flow tracking to placement_fees
ALTER TABLE placement_fees 
ADD COLUMN IF NOT EXISTS cash_flow_status TEXT DEFAULT 'pending';

ALTER TABLE placement_fees 
ADD COLUMN IF NOT EXISTS expected_collection_date DATE;

-- Add check constraint separately to avoid issues if column exists
DO $$ 
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_constraint WHERE conname = 'placement_fees_cash_flow_status_check'
  ) THEN
    ALTER TABLE placement_fees 
    ADD CONSTRAINT placement_fees_cash_flow_status_check 
    CHECK (cash_flow_status IN ('pending', 'invoiced', 'partial', 'collected', 'written_off'));
  END IF;
END $$;

-- Index for cash flow queries
CREATE INDEX IF NOT EXISTS idx_placement_fees_cash_flow 
  ON placement_fees(cash_flow_status, expected_collection_date);

-- Add variance tracking columns if not exists
ALTER TABLE placement_fees 
ADD COLUMN IF NOT EXISTS variance_amount NUMERIC DEFAULT 0;

ALTER TABLE placement_fees 
ADD COLUMN IF NOT EXISTS variance_reason TEXT;

-- Create a view for cash flow pipeline analytics
CREATE OR REPLACE VIEW cash_flow_pipeline AS
SELECT 
  cash_flow_status,
  COUNT(*) as count,
  SUM(fee_amount) as total_amount,
  SUM(CASE WHEN expected_collection_date <= CURRENT_DATE THEN fee_amount ELSE 0 END) as overdue_amount,
  SUM(CASE WHEN expected_collection_date > CURRENT_DATE AND expected_collection_date <= CURRENT_DATE + 30 THEN fee_amount ELSE 0 END) as due_30_days,
  SUM(CASE WHEN expected_collection_date > CURRENT_DATE + 30 AND expected_collection_date <= CURRENT_DATE + 60 THEN fee_amount ELSE 0 END) as due_60_days,
  SUM(CASE WHEN expected_collection_date > CURRENT_DATE + 60 THEN fee_amount ELSE 0 END) as due_90_plus
FROM placement_fees
WHERE status != 'cancelled'
GROUP BY cash_flow_status;

-- Create a view for data integrity checking
CREATE OR REPLACE VIEW data_integrity_issues AS
SELECT 
  'hired_without_fee' as issue_type,
  a.id as record_id,
  a.candidate_full_name as description,
  a.updated_at as detected_at
FROM applications a
LEFT JOIN placement_fees pf ON pf.application_id = a.id
WHERE a.status = 'hired' AND pf.id IS NULL

UNION ALL

SELECT 
  'fee_without_commission' as issue_type,
  pf.id as record_id,
  CONCAT('Fee: €', pf.fee_amount::TEXT) as description,
  pf.created_at as detected_at
FROM placement_fees pf
LEFT JOIN employee_commissions ec ON ec.placement_fee_id = pf.id
WHERE ec.id IS NULL AND pf.status NOT IN ('cancelled', 'pending')

UNION ALL

SELECT 
  'orphaned_commission' as issue_type,
  ec.id as record_id,
  CONCAT('Commission: €', ec.gross_amount::TEXT) as description,
  ec.created_at as detected_at
FROM employee_commissions ec
LEFT JOIN placement_fees pf ON pf.id = ec.placement_fee_id
WHERE ec.placement_fee_id IS NOT NULL AND pf.id IS NULL;-- Fix SECURITY DEFINER SET search_path = '' views by setting security_invoker
ALTER VIEW cash_flow_pipeline SET (security_invoker = on);
ALTER VIEW data_integrity_issues SET (security_invoker = on);-- Fix the trigger function to use correct column name
CREATE OR REPLACE FUNCTION auto_generate_placement_fee()
RETURNS TRIGGER AS $$
DECLARE
  v_fee_percentage DECIMAL(5,2);
  v_fee_amount DECIMAL(12,2);
  v_salary DECIMAL(12,2);
  v_company_id UUID;
  v_splits JSONB;
BEGIN
  IF NEW.status = 'hired' AND (OLD.status IS NULL OR OLD.status != 'hired') THEN
    SELECT company_id INTO v_company_id FROM jobs WHERE id = NEW.job_id;
    
    SELECT COALESCE(pbd.default_fee_percentage, 20.00) INTO v_fee_percentage
    FROM partner_billing_details pbd WHERE pbd.company_id = v_company_id;
    
    -- Fixed: use current_salary_min instead of current_salary
    SELECT COALESCE(current_salary_min, 75000.00) INTO v_salary
    FROM candidate_profiles WHERE id = NEW.candidate_id;
    
    v_fee_amount := v_salary * (v_fee_percentage / 100);
    
    SELECT COALESCE(jsonb_agg(jsonb_build_object(
      'referrer_id', referrer_id,
      'split_percentage', split_percentage,
      'split_amount', ROUND(v_fee_amount * (split_percentage / 100), 2)
    )), '[]'::jsonb) INTO v_splits
    FROM company_referrer_splits
    WHERE company_id = v_company_id AND is_active = true;
    
    INSERT INTO placement_fees (
      application_id, candidate_id, company_id, job_id, hired_date,
      candidate_salary, fee_percentage, fee_amount, fee_percentage_used,
      referrer_splits, status, due_date
    ) VALUES (
      NEW.id, NEW.candidate_id, v_company_id, NEW.job_id, now(),
      v_salary, v_fee_percentage, v_fee_amount, v_fee_percentage,
      v_splits, 'pending', now() + interval '30 days'
    );
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = '';-- Fix the trigger to use companies.placement_fee_percentage as primary source
CREATE OR REPLACE FUNCTION auto_generate_placement_fee()
RETURNS TRIGGER AS $$
DECLARE
  v_fee_percentage DECIMAL(5,2);
  v_fee_amount DECIMAL(12,2);
  v_salary DECIMAL(12,2);
  v_company_id UUID;
  v_splits JSONB;
BEGIN
  IF NEW.status = 'hired' AND (OLD.status IS NULL OR OLD.status != 'hired') THEN
    SELECT company_id INTO v_company_id FROM public.jobs WHERE id = NEW.job_id;
    
    -- Use companies.placement_fee_percentage first, then partner_billing_details, then default 20%
    SELECT COALESCE(
      c.placement_fee_percentage,
      pbd.default_fee_percentage,
      20.00
    ) INTO v_fee_percentage
    FROM public.companies c
    LEFT JOIN public.partner_billing_details pbd ON pbd.company_id = c.id
    WHERE c.id = v_company_id;
    
    SELECT COALESCE(current_salary_min, 75000.00) INTO v_salary
    FROM public.candidate_profiles WHERE id = NEW.candidate_id;
    
    v_fee_amount := v_salary * (v_fee_percentage / 100);
    
    SELECT COALESCE(jsonb_agg(jsonb_build_object(
      'referrer_id', referrer_id,
      'split_percentage', split_percentage,
      'split_amount', ROUND(v_fee_amount * (split_percentage / 100), 2)
    )), '[]'::jsonb) INTO v_splits
    FROM public.company_referrer_splits
    WHERE company_id = v_company_id AND is_active = true;
    
    INSERT INTO public.placement_fees (
      application_id, candidate_id, partner_company_id, job_id, hired_date,
      candidate_salary, fee_percentage, fee_amount, fee_percentage_used,
      referrer_splits, status, payment_due_date
    ) VALUES (
      NEW.id, NEW.candidate_id, v_company_id, NEW.job_id, now(),
      v_salary, v_fee_percentage, v_fee_amount, v_fee_percentage,
      v_splits, 'pending', now() + interval '30 days'
    );
  END IF;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = public;-- Drop broken trigger that references non-existent table
