-- Fix the commission trigger to use valid source_type 'placement' instead of 'placement_fee'
CREATE OR REPLACE FUNCTION calculate_commissions_on_placement_fee()
RETURNS TRIGGER AS $$
DECLARE
  v_job RECORD;
  v_company RECORD;
  v_application RECORD;
  v_strategist_id UUID;
  v_partner_id UUID;
  v_sourcer_id UUID;
  v_strategist_rate NUMERIC;
  v_partner_rate NUMERIC;
  v_sourcer_rate NUMERIC;
  v_strategist_commission NUMERIC;
  v_partner_commission NUMERIC;
  v_sourcer_commission NUMERIC;
  v_placement_fee NUMERIC;
BEGIN
  -- Only process when placement_fee is set or updated
  IF NEW.placement_fee IS NULL OR NEW.placement_fee <= 0 THEN
    RETURN NEW;
  END IF;
  
  -- Skip if placement_fee hasn't changed (for updates)
  IF TG_OP = 'UPDATE' AND OLD.placement_fee = NEW.placement_fee THEN
    RETURN NEW;
  END IF;

  v_placement_fee := NEW.placement_fee;

  -- Get job details
  SELECT j.*, j.company_id, j.owner_id as job_owner_id
  INTO v_job
  FROM jobs j
  WHERE j.id = NEW.job_id;

  IF NOT FOUND THEN
    RAISE WARNING 'Job not found for job_closure: %', NEW.job_id;
    RETURN NEW;
  END IF;

  -- Get company default rates
  SELECT * INTO v_company
  FROM companies
  WHERE id = v_job.company_id;

  -- Determine strategist (job owner)
  v_strategist_id := v_job.job_owner_id;
  
  -- Get strategist commission rate (from profile or company default)
  SELECT COALESCE(p.commission_rate, v_company.default_commission_rate, 10)
  INTO v_strategist_rate
  FROM profiles p
  WHERE p.id = v_strategist_id;

  IF v_strategist_rate IS NULL THEN
    v_strategist_rate := COALESCE(v_company.default_commission_rate, 10);
  END IF;

  -- Calculate and insert strategist commission
  IF v_strategist_id IS NOT NULL THEN
    v_strategist_commission := v_placement_fee * (v_strategist_rate / 100);
    
    INSERT INTO employee_commissions (
      employee_id, job_id, application_id, source_type, 
      commission_rate, base_amount, calculated_amount, status
    ) VALUES (
      v_strategist_id, NEW.job_id, NEW.hired_application_id, 'placement',
      v_strategist_rate, v_placement_fee, v_strategist_commission, 'pending'
    )
    ON CONFLICT (employee_id, application_id, source_type) 
    DO UPDATE SET 
      commission_rate = EXCLUDED.commission_rate,
      base_amount = EXCLUDED.base_amount,
      calculated_amount = EXCLUDED.calculated_amount,
      updated_at = NOW();
  END IF;

  -- Get application details for sourcer
  IF NEW.hired_application_id IS NOT NULL THEN
    SELECT * INTO v_application
    FROM applications
    WHERE id = NEW.hired_application_id;

    -- Determine sourcer (who sourced/referred the candidate)
    v_sourcer_id := v_application.sourced_by;
    
    -- If no sourcer, check if candidate was created by someone
    IF v_sourcer_id IS NULL AND v_application.candidate_id IS NOT NULL THEN
      SELECT created_by INTO v_sourcer_id
      FROM candidate_profiles
      WHERE id = v_application.candidate_id;
    END IF;

    -- Calculate sourcer commission if different from strategist
    IF v_sourcer_id IS NOT NULL AND v_sourcer_id != v_strategist_id THEN
      -- Get sourcer commission rate
      SELECT COALESCE(p.commission_rate, v_company.default_commission_rate, 5)
      INTO v_sourcer_rate
      FROM profiles p
      WHERE p.id = v_sourcer_id;

      IF v_sourcer_rate IS NULL THEN
        v_sourcer_rate := 5; -- Default sourcer rate
      END IF;

      v_sourcer_commission := v_placement_fee * (v_sourcer_rate / 100);
      
      INSERT INTO employee_commissions (
        employee_id, job_id, application_id, source_type,
        commission_rate, base_amount, calculated_amount, status
      ) VALUES (
        v_sourcer_id, NEW.job_id, NEW.hired_application_id, 'placement',
        v_sourcer_rate, v_placement_fee, v_sourcer_commission, 'pending'
      )
      ON CONFLICT (employee_id, application_id, source_type)
      DO UPDATE SET
        commission_rate = EXCLUDED.commission_rate,
        base_amount = EXCLUDED.base_amount,
        calculated_amount = EXCLUDED.calculated_amount,
        updated_at = NOW();
    END IF;
  END IF;

  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = '';-- Fix the calculate_commissions_on_placement_fee function to use correct column name
-- The placement_fees table uses 'fee_amount', not 'placement_fee'

CREATE OR REPLACE FUNCTION public.calculate_commissions_on_placement_fee()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_referral RECORD;
  v_commission_rate NUMERIC;
  v_commission_amount NUMERIC;
  v_tier_name TEXT;
BEGIN
  -- Only process if fee_amount is set and positive
  IF NEW.fee_amount IS NULL OR NEW.fee_amount <= 0 THEN
    RETURN NEW;
  END IF;

  -- Skip if fee_amount hasn't changed (for updates)
  IF TG_OP = 'UPDATE' AND OLD.fee_amount = NEW.fee_amount THEN
    RETURN NEW;
  END IF;

  -- Find the referral associated with this placement
  SELECT r.*, rt.commission_rate, rt.name as tier_name
  INTO v_referral
  FROM referrals r
  LEFT JOIN referral_tiers rt ON r.tier_id = rt.id
  WHERE r.id = NEW.referral_id;

  -- If no referral found, skip commission calculation
  IF v_referral IS NULL THEN
    RETURN NEW;
  END IF;

  -- Use tier commission rate or default to 10%
  v_commission_rate := COALESCE(v_referral.commission_rate, 0.10);
  v_tier_name := COALESCE(v_referral.tier_name, 'Standard');

  -- Calculate commission amount
  v_commission_amount := NEW.fee_amount * v_commission_rate;

  -- Insert or update commission record
  INSERT INTO commissions (
    referral_id,
    placement_fee_id,
    amount,
    rate,
    source_type,
    status,
    notes
  ) VALUES (
    NEW.referral_id,
    NEW.id,
    v_commission_amount,
    v_commission_rate,
    'placement',
    'pending',
    'Auto-calculated from placement fee. Tier: ' || v_tier_name
  )
  ON CONFLICT (placement_fee_id) 
  DO UPDATE SET
    amount = EXCLUDED.amount,
    rate = EXCLUDED.rate,
    notes = EXCLUDED.notes,
    updated_at = now();

  RETURN NEW;
END;
$$;CREATE OR REPLACE FUNCTION public.calculate_pipeline_with_referrals()
RETURNS TABLE(
  gross_pipeline NUMERIC,
  referral_obligations NUMERIC,
  net_pipeline NUMERIC,
  weighted_gross NUMERIC,
  weighted_net NUMERIC,
  deal_count BIGINT
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  RETURN QUERY
  WITH pipeline_values AS (
    SELECT 
      j.id,
      COALESCE(j.deal_value_override, 
        COALESCE(j.salary_max, j.salary_min, 60000) * 
        COALESCE(c.placement_fee_percentage, 20) / 100
      ) as single_deal_value,
      GREATEST(COALESCE(j.target_hire_count, 1) - COALESCE(j.hired_count, 0), 1) as remaining_positions,
      COALESCE(ds.probability_weight, 50) / 100.0 as probability
    FROM jobs j
    LEFT JOIN companies c ON j.company_id = c.id
    LEFT JOIN deal_stages ds ON LOWER(j.deal_stage) = LOWER(ds.name)
    WHERE j.status = 'published' AND j.is_lost = false
  ),
  referral_totals AS (
    SELECT 
      COALESCE(SUM(weighted_amount), 0) as total_weighted,
      COALESCE(SUM(projected_amount), 0) as total_projected
    FROM referral_earnings
    WHERE status IN ('projected', 'qualified')
  )
  SELECT 
    COALESCE(SUM(p.single_deal_value * p.remaining_positions), 0)::NUMERIC as gross_pipeline,
    (SELECT total_projected FROM referral_totals)::NUMERIC as referral_obligations,
    (COALESCE(SUM(p.single_deal_value * p.remaining_positions), 0) - (SELECT total_projected FROM referral_totals))::NUMERIC as net_pipeline,
    COALESCE(SUM(p.single_deal_value * p.remaining_positions * p.probability), 0)::NUMERIC as weighted_gross,
    (COALESCE(SUM(p.single_deal_value * p.remaining_positions * p.probability), 0) - (SELECT total_weighted FROM referral_totals))::NUMERIC as weighted_net,
    COUNT(p.id)::BIGINT as deal_count
  FROM pipeline_values p;
END;
$$;-- Fix the get_deal_stage_for_job function to use jobs.pipeline_stages instead of applications.stages
CREATE OR REPLACE FUNCTION public.get_deal_stage_for_job(p_job_id UUID)
RETURNS TEXT
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_highest_stage TEXT := 'New';
  v_highest_priority INTEGER := 0;
  v_current_stage TEXT;
  v_mapping RECORD;
  v_app RECORD;
  v_job_stages JSONB;
BEGIN
  -- Get the JOB'S pipeline stages (not application.stages!)
  SELECT pipeline_stages INTO v_job_stages
  FROM jobs WHERE id = p_job_id;
  
  -- Handle jobs with no pipeline stages defined
  IF v_job_stages IS NULL OR jsonb_array_length(v_job_stages) = 0 THEN
    RETURN 'New';
  END IF;
  
  -- Loop through all active applications for this job
  FOR v_app IN 
    SELECT 
      a.current_stage_index,
      a.status
    FROM applications a
    WHERE a.job_id = p_job_id
      AND a.status NOT IN ('rejected', 'withdrawn', 'closed')
  LOOP
    -- Get the current stage name from the JOB'S pipeline_stages
    IF v_app.current_stage_index >= 0 
       AND v_app.current_stage_index < jsonb_array_length(v_job_stages) THEN
      v_current_stage := v_job_stages->v_app.current_stage_index->>'name';
      
      IF v_current_stage IS NOT NULL THEN
        -- Find matching mapping with highest priority
        FOR v_mapping IN
          SELECT psm.priority, ds.name as deal_stage_name
          FROM pipeline_stage_mappings psm
          JOIN deal_stages ds ON ds.id = psm.deal_stage_id
          WHERE psm.is_default = true
            AND (
              (psm.match_type = 'exact' AND LOWER(v_current_stage) = LOWER(psm.job_stage_pattern))
              OR (psm.match_type = 'contains' AND LOWER(v_current_stage) LIKE '%' || LOWER(psm.job_stage_pattern) || '%')
              OR (psm.match_type = 'starts_with' AND LOWER(v_current_stage) LIKE LOWER(psm.job_stage_pattern) || '%')
              OR (psm.match_type = 'ends_with' AND LOWER(v_current_stage) LIKE '%' || LOWER(psm.job_stage_pattern))
            )
          ORDER BY psm.priority DESC
          LIMIT 1
        LOOP
          IF v_mapping.priority > v_highest_priority THEN
            v_highest_priority := v_mapping.priority;
            v_highest_stage := v_mapping.deal_stage_name;
          END IF;
        END LOOP;
      END IF;
    END IF;
  END LOOP;
  
  RETURN v_highest_stage;
END;
$$;

