  v_revenue_normalized NUMERIC;
  v_speed_bonus NUMERIC;
BEGIN
  v_revenue_normalized := COALESCE(p_revenue, 0) / 1000;
  v_speed_bonus := CASE 
    WHEN COALESCE(p_avg_time_to_fill, 0) > 0 THEN 100 / p_avg_time_to_fill
    ELSE 0
  END;
  
  RETURN (
    v_revenue_normalized * 0.3 +
