    trend_percent = CASE
      WHEN previous_value IS NULL OR previous_value = 0 THEN 0
      ELSE ROUND(((value - previous_value) / previous_value * 100)::numeric, 2)
    END,
    updated_at = now()
  WHERE trend_direction IS NULL;
END;
