CREATE TABLE IF NOT EXISTS public.freelancer_team_members (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  team_id UUID REFERENCES freelancer_teams(id) ON DELETE CASCADE,
  member_id UUID NOT NULL,
