  leaderboard_type text NOT NULL,
  period_start date NOT NULL,
  period_end date,
  score integer DEFAULT 0,
  rank integer,
  metadata jsonb DEFAULT '{}'::jsonb,
  created_at timestamptz DEFAULT now(),
