-- Fix the broken trigger that references non-existent 'referrals' table
-- Make it safely handle cases where referrals table doesn't exist

CREATE OR REPLACE FUNCTION calculate_commissions_on_placement_fee()
RETURNS TRIGGER AS $$
DECLARE
  v_referral_id UUID;
  v_commission_rate NUMERIC;
  v_commission_amount NUMERIC;
BEGIN
  -- Only process if fee_amount is set and positive
  IF NEW.fee_amount IS NULL OR NEW.fee_amount <= 0 THEN
    RETURN NEW;
  END IF;

  -- Skip if fee_amount hasn't changed (for updates)
  IF TG_OP = 'UPDATE' AND OLD.fee_amount = NEW.fee_amount THEN
    RETURN NEW;
  END IF;

  -- Check if referral_id column exists and has a value
  -- Since referral_id may not exist on the table, safely skip
  BEGIN
    v_referral_id := NEW.referral_id;
  EXCEPTION WHEN undefined_column THEN
    RETURN NEW;
  END;
  
  -- If no referral_id, skip commission calculation
  IF v_referral_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- Try to find referral and calculate commission
  -- Use referral_ledger table instead of non-existent referrals table
  BEGIN
    SELECT COALESCE(rl.payout_percentage, 0.10)
    INTO v_commission_rate
    FROM referral_ledger rl
    WHERE rl.referral_id = v_referral_id
    LIMIT 1;
    
    IF v_commission_rate IS NOT NULL THEN
      v_commission_amount := NEW.fee_amount * v_commission_rate;
      
      -- Update referral_ledger with earnings if it exists
      UPDATE referral_ledger
      SET realized_earnings = COALESCE(realized_earnings, 0) + v_commission_amount,
          updated_at = now()
      WHERE referral_id = v_referral_id;
    END IF;
  EXCEPTION WHEN undefined_table THEN
    -- Table doesn't exist, skip silently
    NULL;
  END;

  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = '';
-- =====================================================
-- VAT Integration: Add VAT columns and tracking tables
-- =====================================================

-- 1. Add VAT columns to moneybird_sales_invoices
ALTER TABLE public.moneybird_sales_invoices 
ADD COLUMN IF NOT EXISTS net_amount NUMERIC NOT NULL DEFAULT 0,
ADD COLUMN IF NOT EXISTS vat_amount NUMERIC NOT NULL DEFAULT 0,
ADD COLUMN IF NOT EXISTS vat_rate NUMERIC DEFAULT 21.00,
ADD COLUMN IF NOT EXISTS vat_type TEXT DEFAULT 'standard';

-- Add comment for vat_type values
COMMENT ON COLUMN public.moneybird_sales_invoices.vat_type IS 'VAT type: standard (21%), reduced (9%), zero (0%), reverse_charge, export, exempt';

-- 2. Create VAT Register table for quarterly BTW-aangifte tracking
CREATE TABLE IF NOT EXISTS public.vat_register (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  period_type TEXT NOT NULL DEFAULT 'quarter',
  period_year INTEGER NOT NULL,
  period_number INTEGER NOT NULL,
  period_start DATE NOT NULL,
  period_end DATE NOT NULL,
  vat_collected NUMERIC NOT NULL DEFAULT 0,
  vat_collected_outstanding NUMERIC NOT NULL DEFAULT 0,
  vat_input NUMERIC NOT NULL DEFAULT 0,
  vat_net_payable NUMERIC GENERATED ALWAYS AS (vat_collected - vat_input) STORED,
  net_revenue NUMERIC NOT NULL DEFAULT 0,
  gross_revenue NUMERIC NOT NULL DEFAULT 0,
  invoice_count INTEGER NOT NULL DEFAULT 0,
  filing_status TEXT DEFAULT 'pending',
  filing_date DATE,
  payment_date DATE,
  notes TEXT,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now(),
  UNIQUE(period_type, period_year, period_number)
);

-- Enable RLS on vat_register
ALTER TABLE public.vat_register ENABLE ROW LEVEL SECURITY;

-- Admin-only policy for VAT register (using user_roles table)
CREATE POLICY "Admins can manage VAT register"
ON public.vat_register
FOR ALL
USING (
  EXISTS (
    SELECT 1 FROM user_roles
    WHERE user_id = auth.uid() AND role = 'admin'
  )
);

-- 3. Add VAT fields to moneybird_financial_metrics
ALTER TABLE public.moneybird_financial_metrics
ADD COLUMN IF NOT EXISTS net_revenue NUMERIC DEFAULT 0,
ADD COLUMN IF NOT EXISTS vat_collected NUMERIC DEFAULT 0,
ADD COLUMN IF NOT EXISTS vat_outstanding NUMERIC DEFAULT 0;

-- 4. Backfill existing invoices with calculated VAT (21% Dutch standard rate)
UPDATE public.moneybird_sales_invoices 
SET 
  net_amount = ROUND(total_amount / 1.21, 2),
  vat_amount = ROUND(total_amount - (total_amount / 1.21), 2),
  vat_rate = 21.00,
  vat_type = 'standard'
WHERE (net_amount = 0 OR net_amount IS NULL) AND total_amount > 0;

-- 5. Create indexes for performance
CREATE INDEX IF NOT EXISTS idx_moneybird_invoices_vat_type 
ON public.moneybird_sales_invoices(vat_type);

CREATE INDEX IF NOT EXISTS idx_vat_register_period 
ON public.vat_register(period_year, period_number);

-- 6. Create trigger for updated_at on vat_register
CREATE OR REPLACE FUNCTION update_vat_register_timestamp()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS update_vat_register_updated_at ON public.vat_register;
CREATE TRIGGER update_vat_register_updated_at
  BEFORE UPDATE ON public.vat_register
  FOR EACH ROW
  EXECUTE FUNCTION update_vat_register_timestamp();-- Create trigger function to auto-generate employee commissions when placement fees are created
CREATE OR REPLACE FUNCTION create_commission_on_placement_fee()
RETURNS TRIGGER AS $$
DECLARE
  v_employee_id UUID;
  v_commission_rate NUMERIC;
  v_commission_amount NUMERIC;
  v_employee_name TEXT;
BEGIN
  -- Skip if no sourcer assigned
  IF NEW.sourced_by IS NULL THEN
    RETURN NEW;
  END IF;

  -- Get the employee profile for the sourcer
  SELECT ep.id, ep.commission_percentage, p.full_name
  INTO v_employee_id, v_commission_rate, v_employee_name
  FROM employee_profiles ep
  JOIN profiles p ON p.id = ep.user_id
  WHERE ep.user_id = NEW.sourced_by
  LIMIT 1;

  -- Skip if no employee profile found or no commission rate
  IF v_employee_id IS NULL OR v_commission_rate IS NULL OR v_commission_rate = 0 THEN
    RETURN NEW;
  END IF;

  -- Calculate commission amount (fee_amount is already net, no VAT on commissions)
  v_commission_amount := NEW.fee_amount * (v_commission_rate / 100);

  -- Insert the commission record
  INSERT INTO employee_commissions (
    employee_id,
    source_type,
    source_id,
    placement_fee_id,
    gross_amount,
    net_amount,
    commission_rate,
    currency_code,
    status,
    notes,
    period_start,
    period_end
  ) VALUES (
    v_employee_id,
    'placement_fee',
    NEW.id,
    NEW.id,
    v_commission_amount,
    v_commission_amount, -- No VAT on employee commissions
    v_commission_rate,
    NEW.currency_code,
    'pending',
    format('Auto-generated commission for %s placement (%.0f%% of €%.2f)', 
           COALESCE(NEW.sourcer_name, v_employee_name), v_commission_rate, NEW.fee_amount),
    date_trunc('month', NEW.hired_date),
    (date_trunc('month', NEW.hired_date) + interval '1 month - 1 day')::date
  );

  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = '';

-- Create trigger on placement_fees table
DROP TRIGGER IF EXISTS trg_create_employee_commission ON placement_fees;
CREATE TRIGGER trg_create_employee_commission
  AFTER INSERT ON placement_fees
  FOR EACH ROW
  EXECUTE FUNCTION create_commission_on_placement_fee();

-- Also create trigger for updates (in case sourced_by is set after creation)
CREATE OR REPLACE FUNCTION update_commission_on_placement_fee_update()
RETURNS TRIGGER AS $$
DECLARE
  v_employee_id UUID;
  v_commission_rate NUMERIC;
  v_commission_amount NUMERIC;
  v_employee_name TEXT;
  v_existing_commission_id UUID;
BEGIN
  -- Check if sourced_by changed
  IF OLD.sourced_by IS DISTINCT FROM NEW.sourced_by OR OLD.fee_amount IS DISTINCT FROM NEW.fee_amount THEN
    -- Delete existing commission for this placement fee
    DELETE FROM employee_commissions WHERE placement_fee_id = NEW.id;
    
    -- Skip if no sourcer assigned
    IF NEW.sourced_by IS NULL THEN
      RETURN NEW;
    END IF;

    -- Get the employee profile for the sourcer
    SELECT ep.id, ep.commission_percentage, p.full_name
    INTO v_employee_id, v_commission_rate, v_employee_name
    FROM employee_profiles ep
    JOIN profiles p ON p.id = ep.user_id
    WHERE ep.user_id = NEW.sourced_by
    LIMIT 1;

    -- Skip if no employee profile found or no commission rate
    IF v_employee_id IS NULL OR v_commission_rate IS NULL OR v_commission_rate = 0 THEN
      RETURN NEW;
    END IF;

    -- Calculate commission amount
    v_commission_amount := NEW.fee_amount * (v_commission_rate / 100);

    -- Insert the commission record
    INSERT INTO employee_commissions (
      employee_id,
      source_type,
      source_id,
      placement_fee_id,
      gross_amount,
      net_amount,
      commission_rate,
      currency_code,
      status,
      notes,
      period_start,
      period_end
    ) VALUES (
      v_employee_id,
      'placement_fee',
      NEW.id,
      NEW.id,
      v_commission_amount,
      v_commission_amount,
      v_commission_rate,
      NEW.currency_code,
      'pending',
      format('Auto-generated commission for %s placement (%.0f%% of €%.2f)', 
             COALESCE(NEW.sourcer_name, v_employee_name), v_commission_rate, NEW.fee_amount),
      date_trunc('month', NEW.hired_date),
      (date_trunc('month', NEW.hired_date) + interval '1 month - 1 day')::date
    );
  END IF;

  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = '';

DROP TRIGGER IF EXISTS trg_update_employee_commission ON placement_fees;
CREATE TRIGGER trg_update_employee_commission
  AFTER UPDATE ON placement_fees
  FOR EACH ROW
  EXECUTE FUNCTION update_commission_on_placement_fee_update();-- Fix trigger function to use correct source_type value
CREATE OR REPLACE FUNCTION create_commission_on_placement_fee()
RETURNS TRIGGER AS $$
DECLARE
  v_employee_id UUID;
  v_commission_rate NUMERIC;
  v_commission_amount NUMERIC;
  v_employee_name TEXT;
  v_candidate_name TEXT;
  v_company_name TEXT;
  v_job_title TEXT;
BEGIN
  -- Skip if no sourcer assigned
  IF NEW.sourced_by IS NULL THEN
    RETURN NEW;
  END IF;

  -- Get the employee profile for the sourcer
  SELECT ep.id, ep.commission_percentage, p.full_name
  INTO v_employee_id, v_commission_rate, v_employee_name
  FROM employee_profiles ep
  JOIN profiles p ON p.id = ep.user_id
  WHERE ep.user_id = NEW.sourced_by
  LIMIT 1;

  -- Skip if no employee profile found or no commission rate
  IF v_employee_id IS NULL OR v_commission_rate IS NULL OR v_commission_rate = 0 THEN
    RETURN NEW;
  END IF;

  -- Get context data
  SELECT full_name INTO v_candidate_name FROM profiles WHERE id = NEW.candidate_id;
  SELECT name INTO v_company_name FROM companies WHERE id = NEW.partner_company_id;
  SELECT title INTO v_job_title FROM jobs WHERE id = NEW.job_id;

  -- Calculate commission amount (fee_amount is already net, no VAT on commissions)
  v_commission_amount := NEW.fee_amount * (v_commission_rate / 100);

  -- Insert the commission record
  INSERT INTO employee_commissions (
    employee_id,
    source_type,
    source_id,
    placement_fee_id,
    placement_fee_base,
    gross_amount,
    net_amount,
    commission_rate,
    status,
    candidate_name,
    company_name,
    job_title,
    period_date,
    notes,
    commission_type
  ) VALUES (
    v_employee_id,
    'placement',
    NEW.id,
    NEW.id,
    NEW.fee_amount,
    v_commission_amount,
    v_commission_amount, -- No VAT on employee commissions
    v_commission_rate,
    'pending',
    v_candidate_name,
    v_company_name,
    v_job_title,
    NEW.hired_date,
    CONCAT('Auto-generated commission for ', COALESCE(NEW.sourcer_name, v_employee_name)),
    'sourcing'
  );

  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = public;

