-- Create a function to get system health with proper security
CREATE FUNCTION public.get_realtime_system_health()
RETURNS TABLE (
  metric_name text,
  value numeric,
  status text,
  last_updated timestamptz
)
LANGUAGE plpgsql
SECURITY INVOKER
SET search_path = public
AS $$
BEGIN
  RETURN QUERY
  SELECT 
    km.metric_name::text,
    km.value::numeric,
    km.status::text,
    km.updated_at::timestamptz
  FROM kpi_metrics km
  WHERE km.category = 'system_health'
  ORDER BY km.metric_name;
END;
$$;

-- Create a function to get KPI summary for dashboard
CREATE OR REPLACE FUNCTION public.get_kpi_dashboard_summary()
RETURNS TABLE (
  domain text,
  total_metrics bigint,
  healthy_count bigint,
  warning_count bigint,
  critical_count bigint,
  last_updated timestamptz
)
LANGUAGE plpgsql
SECURITY INVOKER
SET search_path = public
AS $$
BEGIN
  RETURN QUERY
  SELECT 
    'operations'::text as domain,
    COUNT(*)::bigint as total_metrics,
    COUNT(*) FILTER (WHERE status = 'healthy')::bigint as healthy_count,
    COUNT(*) FILTER (WHERE status = 'warning')::bigint as warning_count,
    COUNT(*) FILTER (WHERE status = 'critical')::bigint as critical_count,
    MAX(updated_at)::timestamptz as last_updated
  FROM kpi_metrics
  UNION ALL
  SELECT 
    'sales'::text,
    COUNT(*)::bigint,
    COUNT(*) FILTER (WHERE status = 'healthy')::bigint,
    COUNT(*) FILTER (WHERE status = 'warning')::bigint,
    COUNT(*) FILTER (WHERE status = 'critical')::bigint,
    MAX(updated_at)::timestamptz
  FROM sales_kpi_metrics
  UNION ALL
  SELECT 
    'website'::text,
    COUNT(*)::bigint,
    COUNT(*) FILTER (WHERE status = 'healthy')::bigint,
    COUNT(*) FILTER (WHERE status = 'warning')::bigint,
    COUNT(*) FILTER (WHERE status = 'critical')::bigint,
    MAX(updated_at)::timestamptz
  FROM web_kpi_metrics;
END;
$$;

-- Create SLA monitoring function
CREATE OR REPLACE FUNCTION public.get_kpi_sla_status()
RETURNS TABLE (
  domain text,
  freshness_minutes numeric,
  is_stale boolean,
  sla_status text
)
LANGUAGE plpgsql
SECURITY INVOKER
SET search_path = public
AS $$
BEGIN
  RETURN QUERY
  SELECT 
    'operations'::text,
    EXTRACT(EPOCH FROM (NOW() - MAX(updated_at))) / 60 as freshness_minutes,
    MAX(updated_at) < NOW() - INTERVAL '1 hour' as is_stale,
    CASE 
      WHEN MAX(updated_at) >= NOW() - INTERVAL '15 minutes' THEN 'fresh'
      WHEN MAX(updated_at) >= NOW() - INTERVAL '1 hour' THEN 'stale'
      ELSE 'critical'
    END as sla_status
  FROM kpi_metrics
  UNION ALL
  SELECT 
    'sales'::text,
    EXTRACT(EPOCH FROM (NOW() - MAX(updated_at))) / 60,
    MAX(updated_at) < NOW() - INTERVAL '1 hour',
    CASE 
      WHEN MAX(updated_at) >= NOW() - INTERVAL '15 minutes' THEN 'fresh'
      WHEN MAX(updated_at) >= NOW() - INTERVAL '1 hour' THEN 'stale'
      ELSE 'critical'
    END
  FROM sales_kpi_metrics
  UNION ALL
  SELECT 
    'website'::text,
    EXTRACT(EPOCH FROM (NOW() - MAX(updated_at))) / 60,
    MAX(updated_at) < NOW() - INTERVAL '1 hour',
    CASE 
      WHEN MAX(updated_at) >= NOW() - INTERVAL '15 minutes' THEN 'fresh'
      WHEN MAX(updated_at) >= NOW() - INTERVAL '1 hour' THEN 'stale'
      ELSE 'critical'
    END
  FROM web_kpi_metrics;
END;
$$;

COMMENT ON FUNCTION public.get_kpi_dashboard_summary() IS 'Returns aggregated KPI health summary by domain for dashboard display';
COMMENT ON FUNCTION public.get_kpi_sla_status() IS 'Returns SLA status for each KPI domain showing data freshness';
COMMENT ON FUNCTION public.get_realtime_system_health() IS 'Returns current system health metrics with proper security';-- Phase 2: SLA Monitoring & Structured Logging Infrastructure

-- 1. Create kpi_execution_events table for structured logging
CREATE TABLE IF NOT EXISTS public.kpi_execution_events (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  event_type TEXT NOT NULL, -- 'start', 'success', 'failure', 'circuit_open', 'circuit_close'
  function_name TEXT NOT NULL,
  domain TEXT,
  severity TEXT DEFAULT 'info', -- 'debug', 'info', 'warn', 'error', 'critical'
  message TEXT,
  metadata JSONB DEFAULT '{}',
  duration_ms INTEGER,
  metrics_count INTEGER,
  error_message TEXT,
  trace_id UUID, -- For correlating related events
  created_at TIMESTAMPTZ DEFAULT now()
);

-- 2. Create circuit_breaker_state table for circuit breaker pattern
CREATE TABLE IF NOT EXISTS public.circuit_breaker_state (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  function_name TEXT UNIQUE NOT NULL,
  state TEXT NOT NULL DEFAULT 'closed', -- 'closed', 'open', 'half_open'
  failure_count INTEGER DEFAULT 0,
  success_count INTEGER DEFAULT 0,
  last_failure_at TIMESTAMPTZ,
  last_success_at TIMESTAMPTZ,
  opened_at TIMESTAMPTZ,
  next_retry_at TIMESTAMPTZ,
  failure_threshold INTEGER DEFAULT 5,
  recovery_timeout_seconds INTEGER DEFAULT 60,
  metadata JSONB DEFAULT '{}',
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now()
);

-- 3. Create kpi_sla_config table for SLA thresholds
CREATE TABLE IF NOT EXISTS public.kpi_sla_config (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  domain TEXT NOT NULL,
  max_stale_minutes INTEGER DEFAULT 60, -- Data considered stale after this
  target_calculation_time_ms INTEGER DEFAULT 5000, -- Target time for calculations
  min_success_rate NUMERIC(5,2) DEFAULT 99.00, -- Minimum success rate %
  alert_on_breach BOOLEAN DEFAULT true,
  created_at TIMESTAMPTZ DEFAULT now(),
  updated_at TIMESTAMPTZ DEFAULT now(),
  UNIQUE(domain)
);

