RETURNS void AS $$
BEGIN
  DELETE FROM query_intent_cache WHERE expires_at < now();
  DELETE FROM embedding_cache WHERE expires_at < now();
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = '';
