  key_facts_preserved INTEGER,
  key_facts_total INTEGER,
  token_count_original INTEGER NOT NULL,
  token_count_compressed INTEGER NOT NULL,
  cost_savings_usd DECIMAL(10,6),
  quality_score DECIMAL(5,4),
