-- Create a function to get relationship health dashboard data with resolved names
CREATE OR REPLACE FUNCTION get_relationship_health_dashboard(
  p_entity_type text DEFAULT NULL,
  p_risk_filter text DEFAULT NULL,
  p_limit integer DEFAULT 50,
  p_offset integer DEFAULT 0
)
RETURNS TABLE (
  id uuid,
  entity_type communication_entity_type,
  entity_id uuid,
  owner_id uuid,
  entity_name text,
  entity_email text,
  entity_avatar text,
  total_communications integer,
  inbound_count integer,
  outbound_count integer,
  engagement_score numeric,
  response_rate numeric,
  avg_sentiment numeric,
  sentiment_trend text,
  last_inbound_at timestamptz,
  last_outbound_at timestamptz,
  days_since_contact integer,
  risk_level relationship_risk_level,
  health_score numeric,
  recommended_action text,
  updated_at timestamptz
)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  RETURN QUERY
  SELECT
    r.id,
    r.entity_type,
    r.entity_id,
    r.owner_id,
    -- Resolve Entity Name
    COALESCE(
      CASE 
        WHEN r.entity_type = 'candidate' THEN cp.full_name
        WHEN r.entity_type = 'company' THEN c.name
        WHEN r.entity_type = 'prospect' THEN pr.full_name
        WHEN r.entity_type IN ('internal', 'partner', 'stakeholder') THEN p.full_name
        ELSE 'Unknown Entity'
      END,
      'Unknown ' || INITCAP(r.entity_type::text)
    ) as entity_name,
    
    -- Resolve Entity Email/Contact info (Optional, useful for UI)
    COALESCE(
      CASE 
        WHEN r.entity_type = 'candidate' THEN cp.email
        WHEN r.entity_type = 'company' THEN NULL -- Companies don't have direct email usually
        WHEN r.entity_type = 'prospect' THEN pr.email
        WHEN r.entity_type IN ('internal', 'partner', 'stakeholder') THEN p.email
        ELSE NULL
      END
    ) as entity_email,

    -- Resolve Avatar (Optional)
    COALESCE(
      CASE 
        WHEN r.entity_type IN ('internal', 'partner', 'stakeholder') THEN p.avatar_url
        WHEN r.entity_type = 'candidate' THEN cp.avatar_url
        WHEN r.entity_type = 'company' THEN c.logo_url
        ELSE NULL
      END
    ) as entity_avatar,

    r.total_communications,
    r.inbound_count,
    r.outbound_count,
    r.engagement_score,
    r.response_rate,
    r.avg_sentiment,
    r.sentiment_trend,
    r.last_inbound_at,
    r.last_outbound_at,
    r.days_since_contact,
    r.risk_level,
    r.health_score,
    r.recommended_action,
    r.updated_at
  FROM
    communication_relationship_scores r
    -- Joins
    LEFT JOIN candidate_profiles cp ON r.entity_type = 'candidate' AND r.entity_id = cp.id
    LEFT JOIN companies c ON r.entity_type = 'company' AND r.entity_id = c.id
    LEFT JOIN crm_prospects pr ON r.entity_type = 'prospect' AND r.entity_id = pr.id
    LEFT JOIN profiles p ON r.entity_type IN ('internal', 'partner', 'stakeholder') AND r.entity_id = p.id
  WHERE
    (p_entity_type IS NULL OR r.entity_type::text = p_entity_type)
    AND
    (p_risk_filter IS NULL OR p_risk_filter = 'all' OR r.risk_level::text = p_risk_filter)
  ORDER BY
    r.risk_level::text = 'critical' DESC,
    r.risk_level::text = 'high' DESC,
    r.health_score ASC
  LIMIT p_limit
  OFFSET p_offset;
END;
$$;
-- Create Entity Relationships Table (The Core of the Knowledge Graph)
create table if not exists "public"."entity_relationships" (
  "id" uuid not null default gen_random_uuid(),
  "source_type" text not null, -- 'candidate', 'company', 'transcript', 'user', 'meeting'
  "source_id" text not null,   -- UUID or unique string
  "target_type" text not null, -- 'skill', 'topic', 'pain_point', 'company', 'candidate'
  "target_id" text not null,   -- Normalized ID (e.g., 'react', 'budget_cuts')
  "relationship_type" text not null, -- 'has_skill', 'interested_in', 'struggling_with', 'works_at'
  "strength_score" numeric default 0.5,
  "evidence" jsonb default '{}'::jsonb, -- Store source text, meeting_id, etc.
  "created_at" timestamp with time zone not null default now(),
  constraint "entity_relationships_pkey" primary key ("id"),
  constraint "entity_relationships_unique_edge" unique ("source_type", "source_id", "target_type", "target_id", "relationship_type")
);

-- Index for fast traversal
create index if not exists "idx_entity_rel_source" on "public"."entity_relationships" ("source_type", "source_id");
create index if not exists "idx_entity_rel_target" on "public"."entity_relationships" ("target_type", "target_id");
create index if not exists "idx_entity_rel_type" on "public"."entity_relationships" ("relationship_type");

-- Enable RLS
alter table "public"."entity_relationships" enable row level security;
create policy "Allow all for authenticated" on "public"."entity_relationships" for all using (auth.role() = 'authenticated');

-- RPC Function: Match Entity Relationships (The "Graph Walk")
-- Input: List of concepts (e.g. ['react', 'google'])
-- Output: List of text facts describing connections
create or replace function match_entity_relationships(
    entities text[], 
    match_threshold numeric default 0.5
)
returns table (
    source_type text,
    source_id text,
    relationship text,
    target text,
    content text,
    similarity numeric
) 
language plpgsql
as $$
begin
    return query
    with relevant_edges as (
        select 
            er.source_type,
            er.source_id,
            er.target_type,
            er.target_id,
            er.relationship_type,
            er.strength_score,
            er.evidence
        from 
            entity_relationships er
        where 
            -- Direct match on target (e.g. target='react')
            er.target_id = any(entities)
            -- OR Direct match on source (e.g. source='google')
            or er.source_id = any(entities)
    )
    select 
        re.source_type,
        re.source_id,
        re.relationship_type as relationship,
        re.target_id as target,
        case 
            when re.source_type = 'candidate' then 'Candidate ' || re.source_id || ' ' || re.relationship_type || ' ' || re.target_id
            when re.source_type = 'company' then 'Company ' || re.source_id || ' ' || re.relationship_type || ' ' || re.target_id
            else re.source_type || ' ' || re.relationship_type || ' ' || re.target_id
        end as content,
        re.strength_score as similarity
    from 
        relevant_edges re
    where 
        re.strength_score >= match_threshold
    order by 
        re.strength_score desc
    limit 20;
end;
$$;
